// FALLBACK MELHORADO: requer_resposta por heuristicas
// Regras: so marca requer_resposta=true quando eh uma demanda REAL
// do mentorado que a equipe precisa responder/agir
const items = $input.all();

const CONFIRMACOES = /^(ok|valeu|obrigad|show|boa|blz|tmj|beleza|perfeito|otimo|certo|entendi|sim|nao|pode|claro|bora|vamos|combinado|fechou|massa|top|dahora|boa tarde|boa noite|bom dia|oi|oie|oiee|ola|eai|fala|hey)/i;

const SOCIAL = /^(bom dia|boa tarde|boa noite|feliz|parabens|obrigad|valeu|tmj|amem|deus|amen|gratidao)/i;

// Perguntas retoricas / confirmacoes com ?
const FALSA_PERGUNTA = /^(pode ser|ne|neh|ta bom|ta bem|certo|sim|nao|ok|beleza|combinado|vamos|bora|entendi|show)\??$/i;

const HELP_KEYWORDS = ["ajuda", "como faz", "nao sei", "não sei", "duvida", "dúvida", "preciso", "urgente", "problema", "nao consigo", "não consigo", "travado", "parado", "como que", "me explica", "nao entendi", "não entendi"];

for (const item of items) {
  const d = item.json;

  // Se ja foi classificado, nao mexer
  if (d.requer_resposta === true || d.requer_resposta === false) continue;

  const conteudo = (d.conteudo || d.content || "").trim();
  const conteudoLower = conteudo.toLowerCase();
  const tipo = (d.tipo_interacao || d.classificacao || "").toLowerCase();
  const isEquipe = d.eh_equipe === true;

  // REGRA 1: Equipe nunca gera pendencia PRA equipe
  if (isEquipe) {
    d.requer_resposta = false;
    d._requer_resposta_source = "is_equipe";
    continue;
  }

  // REGRA 2: Mensagem curta demais (< 15 chars) = nao eh pendencia
  if (conteudo.length < 15) {
    d.requer_resposta = false;
    d._requer_resposta_source = "too_short";
    continue;
  }

  // REGRA 3: Confirmacao / saudacao = nao eh pendencia
  if (CONFIRMACOES.test(conteudoLower) || SOCIAL.test(conteudoLower)) {
    d.requer_resposta = false;
    d._requer_resposta_source = "social_confirmacao";
    continue;
  }

  // REGRA 4: Tipo social / informativo = nao eh pendencia
  if (["social", "informativo", "saudacao", "agradecimento", "celebracao", "confirmacao"].some(t => tipo.includes(t))) {
    d.requer_resposta = false;
    d._requer_resposta_source = "social_tipo";
    continue;
  }

  // REGRA 5: Tem ? mas eh falsa pergunta ("pode ser?", "ne?")
  if (conteudo.includes("?")) {
    const limpo = conteudoLower.replace(/[?!.,]/g, "").trim();
    if (FALSA_PERGUNTA.test(limpo) || limpo.length < 15) {
      d.requer_resposta = false;
      d._requer_resposta_source = "falsa_pergunta";
      continue;
    }
  }

  // REGRA 6: Link puro (google docs, zoom, youtube) = entrega, nao pergunta
  if (/^https?:\/\//i.test(conteudoLower.trim()) && !conteudo.includes("?")) {
    d.requer_resposta = false;
    d._requer_resposta_source = "link_only";
    continue;
  }

  // REGRA 7: Audio/imagem/video sem texto = nao sabemos, default false
  if (["audio", "image", "video", "sticker", "document"].includes(d.message_type) && conteudo.length < 5) {
    d.requer_resposta = false;
    d._requer_resposta_source = "media_sem_texto";
    continue;
  }

  // REGRA 8: Tipo duvida/bloqueio/solicitacao COM pergunta real = pendencia
  if (["duvida", "bloqueio", "solicitacao", "pedido"].some(t => tipo.includes(t))) {
    if (conteudo.includes("?") || HELP_KEYWORDS.some(kw => conteudoLower.includes(kw))) {
      d.requer_resposta = true;
      d._requer_resposta_source = "tipo_com_pergunta";
      continue;
    }
    d.requer_resposta = false;
    d._requer_resposta_source = "tipo_sem_pergunta";
    continue;
  }

  // REGRA 9: Keywords de ajuda = pendencia
  if (HELP_KEYWORDS.some(kw => conteudoLower.includes(kw))) {
    d.requer_resposta = true;
    d._requer_resposta_source = "keyword_match";
    continue;
  }

  // REGRA 10: Pergunta real (? com conteudo substancial > 25 chars)
  if (conteudo.includes("?") && conteudo.length > 25) {
    d.requer_resposta = true;
    d._requer_resposta_source = "pergunta_substancial";
    continue;
  }

  // DEFAULT: nao eh pendencia
  d.requer_resposta = false;
  d._requer_resposta_source = "default_no";
}

return items;
